SELECT

FROM mall_product

    (is_deleted IS NULL OR is_deleted = 0)

        AND id = #{request.id}


        AND name LIKE CONCAT('%', #{request.name}, '%')


        AND id IN (
        SELECT DISTINCT rel.product_id
        FROM mall_product_category_rel rel
        WHERE (rel.is_deleted IS NULL OR rel.is_deleted = 0)
        AND rel.category_id = #{request.categoryId}
        )



            AND id IN (
            SELECT DISTINCT rel.product_id
            FROM mall_product_tag_rel rel
            INNER JOIN mall_product_tag tag ON rel.tag_id = tag.id
            WHERE (tag.is_deleted IS NULL OR tag.is_deleted = 0)
            AND tag.type_id = #{group.typeId}
            AND rel.tag_id IN

                #{tagId}

            )



        AND status = #{request.status}


        AND price >= #{request.minPrice}


        AND price <= #{request.maxPrice}


ORDER BY sort ASC, create_time DESC

SELECT p.id, p.name, p.category_id, p.unit, p.price, p.stock, p.sort, p.status, p.delivery_type, p.coupon_enabled, p.version, p.create_time, p.update_time, p.create_by, p.update_by, NULL AS image_url, md.common_name AS med_common_name, md.composition AS med_composition, md.characteristics AS med_characteristics, md.packaging AS med_packaging, md.validity_period AS med_validity_period, md.storage_conditions AS med_storage_conditions, md.production_unit AS med_production_unit, md.approval_number AS med_approval_number, md.executive_standard AS med_executive_standard, md.origin_type AS med_origin_type, md.is_outpatient_medicine AS med_is_outpatient_medicine, md.warm_tips AS med_warm_tips, md.brand AS med_brand, md.drug_category AS med_drug_category, md.efficacy AS med_efficacy, md.usage_method AS med_usage_method, md.adverse_reactions AS med_adverse_reactions, md.precautions AS med_precautions, md.taboo AS med_taboo, md.instruction AS med_instruction FROM mall_product p LEFT JOIN drug_detail md ON p.id = md.product_id AND (md.is_deleted IS NULL OR md.is_deleted = 0)
(p.is_deleted IS NULL OR p.is_deleted = 0)
AND p.id = #{request.id}
AND p.name LIKE CONCAT('%', #{request.name}, '%')
AND p.id IN ( SELECT DISTINCT rel.product_id FROM mall_product_category_rel rel WHERE (rel.is_deleted IS NULL OR rel.is_deleted = 0) AND rel.category_id = #{request.categoryId} )
AND p.id IN ( SELECT DISTINCT rel.product_id FROM mall_product_tag_rel rel INNER JOIN mall_product_tag tag ON rel.tag_id = tag.id WHERE (tag.is_deleted IS NULL OR tag.is_deleted = 0) AND tag.type_id = #{group.typeId} AND rel.tag_id IN
#{tagId}
)
AND p.status = #{request.status}
AND p.price >= #{request.minPrice}
AND p.price <= #{request.maxPrice}
ORDER BY p.sort , p.create_time DESC

SELECT p.id, p.name, p.category_id, p.unit, p.price, p.stock, p.sort, p.status, p.delivery_type, p.coupon_enabled, p.version, p.create_time, p.update_time, p.create_by, p.update_by, NULL AS image_url, md.common_name AS med_common_name, md.composition AS med_composition, md.characteristics AS med_characteristics, md.packaging AS med_packaging, md.validity_period AS med_validity_period, md.storage_conditions AS med_storage_conditions, md.production_unit AS med_production_unit, md.approval_number AS med_approval_number, md.executive_standard AS med_executive_standard, md.origin_type AS med_origin_type, md.is_outpatient_medicine AS med_is_outpatient_medicine, md.warm_tips AS med_warm_tips, md.brand AS med_brand, md.drug_category AS med_drug_category, md.efficacy AS med_efficacy, md.usage_method AS med_usage_method, md.adverse_reactions AS med_adverse_reactions, md.precautions AS med_precautions, md.taboo AS med_taboo, md.instruction AS med_instruction FROM mall_product p LEFT JOIN drug_detail md ON p.id = md.product_id AND (md.is_deleted IS NULL OR md.is_deleted = 0) WHERE (p.is_deleted IS NULL OR p.is_deleted = 0) AND p.id IN
#{id}
ORDER BY p.id
